sql:
SELECT publication_title, doi 
FROM mutation_publications 
WHERE journal = 'Nature Genetics';

SELECT mutation_id, functional_impact_score
FROM mutations
WHERE functional_impact_score = (
  SELECT MAX(functional_impact_score) 
  FROM mutations
);

SELECT COUNT(stat_id) AS total_statistics
FROM mutation_statistics
WHERE mutation_id = 0 AND calculation_date >= '2023-01-01';

SELECT COUNT(*) AS mutation_sources_count
FROM mutation_sources
WHERE mutation_id = 0;

SELECT MAX(statistic_value) AS max_frequency
FROM mutation_statistics
WHERE statistic_type = 'frequency';

SELECT COUNT(*) AS comment_count
FROM mutation_comments
WHERE is_private = 0;

SELECT statistic_value
FROM mutation_statistics
WHERE mutation_id = 0 AND statistic_type = 'frequency';

SELECT publication_title
FROM mutation_publications
WHERE publication_id = 1;

SELECT MAX(max_functional_impact_score) AS highest_max_functional_impact_score
FROM (
  SELECT species, MAX(functional_impact_score) AS max_functional_impact_score
  FROM mutations
  GROUP BY species
) AS max_scores;

SELECT COUNT(*) AS total_clinical_impact_statistics
FROM mutation_statistics
WHERE statistic_type = 'clinical_impact';

SELECT source_description 
FROM mutation_sources 
WHERE source_id = 0;

SELECT tag_text
FROM mutation_tags
WHERE mutation_id = 0 AND tag_type = 'clinical';
